Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int countOccurrences(std::string filename, std::string word);

int main() {
    std::string filename;
    std::string word;

    std::cout << "Enter the name of the input file: ";
    std::cin >> filename;

    std::cout << "Enter the word to search for: ";
    std::cin >> word;

    int count = countOccurrences(filename, word);

    std::cout << "The word \"" << word << "\" occurs " << count << " times in the file \"" << filename << "\".\n";

    return 0;
}

int countOccurrences(std::string filename, std::string word) {
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error opening file: " << filename << "\n";
        return -1;
    }

    int lineNumber = 0;
    int occurrenceCount = 0;
    std::string line;

    while (std::getline(file, line)) {
        lineNumber++;
        size_t pos = 0;
        while ((pos = line.find(word, pos)) != std::string::npos) {
            occurrenceCount++;
            pos += word.length();
        }
    }

    file.close();
    return occurrenceCount;
}
```

To use this program, simply compile it using a C++ compiler like g++, and then run the resulting executable. When prompted, enter the name of the input file and the word you want to search for. The program will output the number of times the specified word appears in the file.

Note that this program is case-sensitive and does not handle punctuation or multiple words as a single search term (e.g., it would count "hello" and "hello!" as two occurrences). You can extend the functionality by adding additional processing to the `countOccurrences` function.

def longest_common_subsequence(s1, s2):
    # Create a matrix to store lengths of longest common subsequences for substrings
    dp = [[0] * (len(s2) + 1) for _ in range(len(s1) + 1)]

    # Iterate through both strings and fill the matrix
    for i in range(1, len(s1) + 1):
        for j in range(1, len(s2) + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # Reconstruct the longest common subsequence from the matrix
    lcs = []
    i, j = len(s1), len(s2)
    while i > 0 and j > 0:
        if s1[i - 1] == s2[j - 1]:
            lcs.append(s1[i - 1])
            i -= 1
            j -= 1
        elif dp[i - 1][j] > dp[i][j - 1]:
            j -= 1
        else:
            i -= 1

    return ''.join(reversed(lcs))


